+public class CustomLoadee {
+    public CustomLoadee() {
+        hotspot2();
+    }
+
+    static volatile int x;
+    static void hotspot2() {
+        long start = System.currentTimeMillis();
+        // run this loop long enough (400ms) for it to be JIT compiled.
+        while (System.currentTimeMillis() - start < 400) {
+            x += 1;
+        }
+    }
+}
